import{_ as o,C as a,o as i,c as r,j as e,a as s,E as n,ak as c}from"./chunks/framework.sV-XtlWr.js";const b=JSON.parse('{"title":"Configuration reference","description":"","frontmatter":{"title":"Configuration reference","lang":"en-US","editLink":false},"headers":[],"relativePath":"configuration.md","filePath":"configuration.md","lastUpdated":null}'),l={name:"configuration.md"};function h(p,t,I,u,_,m){const d=a("ConfigModeSwitch");return i(),r("div",null,[t[0]||(t[0]=e("h1",{id:"configuration-reference",tabindex:"-1"},[s("Configuration reference "),e("a",{class:"header-anchor",href:"#configuration-reference","aria-label":'Permalink to "Configuration reference"'},"​")],-1)),n(d,{mode:"reference"}),t[1]||(t[1]=c('<p>Piwi is configured entirely through environment variables. It runs with <strong>zero configuration</strong> out of the box — SQLite and local file storage are created automatically under <code>.data/</code>. Set variables only to change a default.</p><p>Variables can go in <code>application/.env</code> (see <code>application/.env.example</code>) or be passed to the container/process. Where a value can also be set in the Settings UI, <strong>the environment variable always wins</strong> and the UI shows that field read-only.</p><p>Prefer a guided setup? The <a href="./configuration/generator.html">configuration generator</a> builds a ready-to-paste <code>.env</code>, Docker, Kubernetes or systemd configuration from the same registry as this page — entirely in your browser.</p><div class="tip custom-block"><p class="custom-block-title">Settings UI tooltips</p><p>In the dashboard, every overridable setting shows a help icon next to its label. Hover it to see which <code>PIWI_*</code> env var backs the field, a one-line description, and a link back to this page. Fields that are currently pinned by the environment show a lock badge with the variable name, and the Settings nav marks env-managed pages with a lock icon. This page is generated from the typed registry in <code>application/shared/piwi-env-vars.ts</code> (version 0.18.1), the same source those tooltips use.</p></div><h2 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to &quot;General&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Variable</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code id="piwi-site-url">PIWI_SITE_URL</code></td><td>—</td><td>Public base URL of the instance (e.g. <a href="https://piwi.example.com" target="_blank" rel="noreferrer">https://piwi.example.com</a>). Used to build links in emails. When unset, links in emails point to <a href="http://localhost:3000" target="_blank" rel="noreferrer">http://localhost:3000</a> and OAuth callback URLs are inferred from the request host — set it when running behind a reverse proxy.</td></tr><tr><td><code id="piwi-secret-key">PIWI_SECRET_KEY</code></td><td>—</td><td>Master key for AES-256-GCM encryption of secrets stored in the database (AI API keys, webhook/SCM secrets). Strongly recommended in production. Falls back to an insecure built-in development key (with a startup warning in production). Generate one with <code>node -e &quot;console.log(require(&#39;node:crypto&#39;).randomBytes(32).toString(&#39;hex&#39;))&quot;</code>.</td></tr></tbody></table><h2 id="database" tabindex="-1">Database <a class="header-anchor" href="#database" aria-label="Permalink to &quot;Database&quot;">​</a></h2><p>Piwi uses SQLite by default. Setting <code>PIWI_DATABASE_URL</code> switches it to PostgreSQL; migrations run automatically on startup.</p><table tabindex="0"><thead><tr><th>Variable</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code id="piwi-database-path">PIWI_DATABASE_PATH</code></td><td><code>.data/piwi.db</code></td><td>Path to the SQLite database file (used when PIWI_DATABASE_URL is not set).</td></tr><tr><td><code id="piwi-database-url">PIWI_DATABASE_URL</code></td><td>—</td><td>PostgreSQL connection string. When set, PostgreSQL is used instead of SQLite and migrations run automatically on startup. See <a href="./deployment.html#docker-compose-with-postgresql">details</a>.</td></tr><tr><td><code id="piwi-retention-days">PIWI_RETENTION_DAYS</code></td><td>—</td><td>Days of test-run history the nightly retention sweep keeps. Unset or 0 disables automatic run pruning (the default — pruning is opt-in). See <a href="./storage.html#data-retention">details</a>.</td></tr><tr><td><code id="piwi-retention-notification-days">PIWI_RETENTION_NOTIFICATION_DAYS</code></td><td><code>30</code></td><td>Days to keep sent/failed notification outbox rows before the nightly sweep prunes them (default 30; 0 keeps them forever).</td></tr><tr><td><code id="piwi-retention-diagnosis-versions">PIWI_RETENTION_DIAGNOSIS_VERSIONS</code></td><td><code>20</code></td><td>AI-diagnosis history versions kept per diagnosis by the nightly sweep (default 20; 0 disables capping).</td></tr></tbody></table><p>See <a href="./deployment.html">Deployment</a> for PostgreSQL setup and <a href="./storage.html#data-retention">Storage → Data retention</a> for how the nightly sweep works.</p><h2 id="storage" tabindex="-1">Storage <a class="header-anchor" href="#storage" aria-label="Permalink to &quot;Storage&quot;">​</a></h2><p>Controls where test artifacts (HTML reports, traces, attachments) are stored.</p><table tabindex="0"><thead><tr><th>Variable</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code id="piwi-storage-type">PIWI_STORAGE_TYPE</code></td><td><code>local</code></td><td>Storage backend for test artifacts (HTML reports, traces, attachments): &quot;local&quot; or &quot;s3&quot;. Only the exact value <code>s3</code> selects S3; any other value falls back to local storage.</td></tr><tr><td><code id="piwi-storage-path">PIWI_STORAGE_PATH</code></td><td><code>.data/storage</code></td><td>Directory for local file storage (when PIWI_STORAGE_TYPE is &quot;local&quot;).</td></tr><tr><td><code id="piwi-s3-bucket">PIWI_S3_BUCKET</code></td><td>—</td><td>S3 bucket name for artifact storage (when PIWI_STORAGE_TYPE is &quot;s3&quot;). See <a href="./storage.html#s3-compatible-storage">details</a>.</td></tr><tr><td><code id="piwi-s3-region">PIWI_S3_REGION</code></td><td>—</td><td>S3 bucket region (when PIWI_STORAGE_TYPE is &quot;s3&quot;).</td></tr><tr><td><code id="piwi-s3-access-key-id">PIWI_S3_ACCESS_KEY_ID</code></td><td>—</td><td>S3 access key id with write access to the bucket.</td></tr><tr><td><code id="piwi-s3-secret-access-key">PIWI_S3_SECRET_ACCESS_KEY</code></td><td>—</td><td>S3 secret access key.</td></tr><tr><td><code id="piwi-s3-endpoint">PIWI_S3_ENDPOINT</code></td><td>—</td><td>Custom endpoint for S3-compatible services (MinIO, R2, Spaces).</td></tr><tr><td><code id="piwi-s3-force-path-style">PIWI_S3_FORCE_PATH_STYLE</code></td><td>—</td><td>Use path-style addressing (required by some S3-compatible services). Defaults to on when a custom endpoint is set, off otherwise; only the exact value <code>false</code> turns it off explicitly.</td></tr></tbody></table><p>Full details and IAM examples: <a href="./storage.html">Storage configuration</a>.</p><h2 id="authentication" tabindex="-1">Authentication <a class="header-anchor" href="#authentication" aria-label="Permalink to &quot;Authentication&quot;">​</a></h2><p>Authentication is optional and off by default. When disabled, all endpoints behave as a single virtual administrator.</p><table tabindex="0"><thead><tr><th>Variable</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code id="piwi-auth-enabled">PIWI_AUTH_ENABLED</code></td><td><code>false</code></td><td>Set to &quot;true&quot; to enable role-based access control and API keys. Off by default.</td></tr><tr><td><code id="piwi-auth-secret">PIWI_AUTH_SECRET</code></td><td>—</td><td>Secret used to sign/encrypt session cookies. Required when PIWI_AUTH_ENABLED is true. The server refuses to start when auth is enabled and this is unset.</td></tr><tr><td><code id="piwi-oauth-google-client-id">PIWI_OAUTH_GOOGLE_CLIENT_ID</code></td><td>—</td><td>Google OAuth client id (optional single sign-on). See <a href="./authentication.html#oauth-google-github">details</a>.</td></tr><tr><td><code id="piwi-oauth-google-client-secret">PIWI_OAUTH_GOOGLE_CLIENT_SECRET</code></td><td>—</td><td>Google OAuth client secret.</td></tr><tr><td><code id="piwi-oauth-github-client-id">PIWI_OAUTH_GITHUB_CLIENT_ID</code></td><td>—</td><td>GitHub OAuth client id (optional single sign-on). See <a href="./authentication.html#oauth-google-github">details</a>.</td></tr><tr><td><code id="piwi-oauth-github-client-secret">PIWI_OAUTH_GITHUB_CLIENT_SECRET</code></td><td>—</td><td>GitHub OAuth client secret.</td></tr><tr><td><code id="piwi-oauth-allowed-domains">PIWI_OAUTH_ALLOWED_DOMAINS</code></td><td>—</td><td>Comma-separated verified email domains allowed to sign in via OAuth (all providers). Only verified emails in these domains are accepted. Empty means no domain restriction.</td></tr><tr><td><code id="piwi-oauth-github-allowed-orgs">PIWI_OAUTH_GITHUB_ALLOWED_ORGS</code></td><td>—</td><td>Comma-separated GitHub org logins a user must belong to (requests read:org scope).</td></tr></tbody></table><blockquote><p>Behind a reverse proxy, set <code>PIWI_SITE_URL</code> so the OAuth <code>redirect_uri</code> is built from your public URL and matches what you registered with the provider (instead of being inferred from the request <code>Host</code>).</p></blockquote><p>See <a href="./authentication.html">Authentication</a> for roles, API keys, and project assignments.</p><h2 id="wasted-time" tabindex="-1">Wasted time <a class="header-anchor" href="#wasted-time" aria-label="Permalink to &quot;Wasted time&quot;">​</a></h2><p>Controls which Playwright wait steps are counted as &quot;wasted time&quot; on the run timeline and in per-test/run totals. Classification happens when a run is viewed, so changing it re-classifies historical runs immediately.</p><table tabindex="0"><thead><tr><th>Variable</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code id="piwi-wasted-wait-patterns">PIWI_WASTED_WAIT_PATTERNS</code></td><td><code>Wait for timeout*,*waitForTimeout*</code></td><td>Glob patterns (comma or newline separated) defining which wait steps count as wasted time. Locks the UI when set. Case-insensitive globs (<code>*</code> and <code>?</code>) matched against a wait step’s title or source location. Use <code>*</code> to count every wait.</td></tr></tbody></table><p>When unset, configure the patterns from <strong>Settings → Wasted time</strong> (administrator only). The default counts only explicit <code>waitForTimeout</code> sleeps, since framework-injected waits (load-state, wait-for-function) are usually unavoidable.</p><h2 id="ai-diagnosis" tabindex="-1">AI diagnosis <a class="header-anchor" href="#ai-diagnosis" aria-label="Permalink to &quot;AI diagnosis&quot;">​</a></h2><p><code>PIWI_AI_PROVIDER</code> is the master switch: when it is set, AI configuration is environment-managed (the Settings UI shows the fields read-only) and the other <code>PIWI_AI_*</code> variables apply. When it is unset, AI diagnosis is configured from <strong>Settings → AI</strong> instead and the variables below are ignored.</p><table tabindex="0"><thead><tr><th>Variable</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code id="piwi-ai-provider">PIWI_AI_PROVIDER</code></td><td>—</td><td>AI provider for failure diagnosis: &quot;anthropic&quot; or &quot;openai&quot; (OpenAI-compatible).</td></tr><tr><td><code id="piwi-ai-api-key">PIWI_AI_API_KEY</code></td><td>—</td><td>API key for the diagnosis provider. Takes precedence over the DB-stored key. Optional for OpenAI-compatible providers that need no key (e.g. a local model).</td></tr><tr><td><code id="piwi-ai-model">PIWI_AI_MODEL</code></td><td>—</td><td>Diagnosis model name (default: claude-opus-4-8 for Anthropic).</td></tr><tr><td><code id="piwi-ai-base-url">PIWI_AI_BASE_URL</code></td><td>—</td><td>Base URL for OpenAI-compatible providers (e.g. <a href="http://localhost:11434/v1" target="_blank" rel="noreferrer">http://localhost:11434/v1</a>).</td></tr><tr><td><code id="piwi-ai-auto-diagnose">PIWI_AI_AUTO_DIAGNOSE</code></td><td><code>false</code></td><td>Set to &quot;true&quot; to auto-diagnose new failure clusters when a run finishes.</td></tr><tr><td><code id="piwi-ai-auto-diagnose-max">PIWI_AI_AUTO_DIAGNOSE_MAX</code></td><td><code>3</code></td><td>Max clusters auto-diagnosed per finished run (budget cap; default 3).</td></tr><tr><td><code id="piwi-ai-research-provider">PIWI_AI_RESEARCH_PROVIDER</code></td><td>—</td><td>Provider for the optional research (pre-analysis) stage. Falls back to PIWI_AI_PROVIDER.</td></tr><tr><td><code id="piwi-ai-research-model">PIWI_AI_RESEARCH_MODEL</code></td><td>—</td><td>Cheaper/faster model for the research stage. Empty disables the two-stage pipeline.</td></tr><tr><td><code id="piwi-ai-research-base-url">PIWI_AI_RESEARCH_BASE_URL</code></td><td>—</td><td>Base URL for the research-stage provider. Falls back to PIWI_AI_BASE_URL.</td></tr><tr><td><code id="piwi-ai-research-api-key">PIWI_AI_RESEARCH_API_KEY</code></td><td>—</td><td>API key for the research-stage provider. Falls back to PIWI_AI_API_KEY.</td></tr><tr><td><code id="piwi-ai-embedding-provider">PIWI_AI_EMBEDDING_PROVIDER</code></td><td>—</td><td>Provider for embeddings (semantic failure clustering). Falls back to PIWI_AI_PROVIDER. Must resolve to an OpenAI-compatible provider — Anthropic has no embeddings API — so the fallback only helps when the main provider is &quot;openai&quot;.</td></tr><tr><td><code id="piwi-ai-embedding-model">PIWI_AI_EMBEDDING_MODEL</code></td><td>—</td><td>Embedding model name (e.g. text-embedding-3-small). Empty disables semantic clustering (and the embedding fallbacks).</td></tr><tr><td><code id="piwi-ai-embedding-base-url">PIWI_AI_EMBEDDING_BASE_URL</code></td><td>—</td><td>Base URL for the embedding provider. Falls back to PIWI_AI_BASE_URL.</td></tr><tr><td><code id="piwi-ai-embedding-api-key">PIWI_AI_EMBEDDING_API_KEY</code></td><td>—</td><td>API key for the embedding provider. Falls back to PIWI_AI_API_KEY.</td></tr></tbody></table><p>See <a href="./ai-diagnosis.html">AI diagnosis</a> for how diagnosis, the research stage, and semantic clustering work.</p><h2 id="ai-context-limits" tabindex="-1">AI context limits <a class="header-anchor" href="#ai-context-limits" aria-label="Permalink to &quot;AI context limits&quot;">​</a></h2><p>Cap how much evidence (and how many tokens) go into each AI diagnosis. Resolution order: defaults ← values stored from <strong>Settings → AI</strong> ← environment; the environment wins and locks the field in the UI. Values are clamped to the min–max range; a <code>0</code> disables a section only where the minimum is <code>0</code>.</p><table tabindex="0"><thead><tr><th>Variable</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code id="piwi-ai-max-sample-error-chars">PIWI_AI_MAX_SAMPLE_ERROR_CHARS</code></td><td><code>10000</code></td><td>Max characters of raw error text (per error block).</td></tr><tr><td><code id="piwi-ai-max-scm-patch-budget">PIWI_AI_MAX_SCM_PATCH_BUDGET</code></td><td><code>15000</code></td><td>Total characters of diff patches across changed files.</td></tr><tr><td><code id="piwi-ai-max-affected-tests">PIWI_AI_MAX_AFFECTED_TESTS</code></td><td><code>30</code></td><td>Max affected tests listed in the diagnosis context.</td></tr><tr><td><code id="piwi-ai-max-steps">PIWI_AI_MAX_STEPS</code></td><td><code>50</code></td><td>Max recent test steps included.</td></tr><tr><td><code id="piwi-ai-max-console-entries">PIWI_AI_MAX_CONSOLE_ENTRIES</code></td><td><code>30</code></td><td>Max console error/warning entries included.</td></tr><tr><td><code id="piwi-ai-max-console-entry-chars">PIWI_AI_MAX_CONSOLE_ENTRY_CHARS</code></td><td><code>1000</code></td><td>Max characters per console entry.</td></tr><tr><td><code id="piwi-ai-max-network-requests">PIWI_AI_MAX_NETWORK_REQUESTS</code></td><td><code>25</code></td><td>Max failed network requests included.</td></tr><tr><td><code id="piwi-ai-max-aria-snapshot-chars">PIWI_AI_MAX_ARIA_SNAPSHOT_CHARS</code></td><td><code>12000</code></td><td>Max characters of the page ARIA snapshot.</td></tr><tr><td><code id="piwi-ai-max-test-source-chars">PIWI_AI_MAX_TEST_SOURCE_CHARS</code></td><td><code>8000</code></td><td>Max characters of the test source snippet.</td></tr><tr><td><code id="piwi-ai-max-source-files">PIWI_AI_MAX_SOURCE_FILES</code></td><td><code>4</code></td><td>Max full source files fetched from SCM to ground patches (0 disables).</td></tr><tr><td><code id="piwi-ai-max-source-file-chars">PIWI_AI_MAX_SOURCE_FILE_CHARS</code></td><td><code>12000</code></td><td>Max characters per fetched full source file.</td></tr><tr><td><code id="piwi-ai-max-server-log-entries">PIWI_AI_MAX_SERVER_LOG_ENTRIES</code></td><td><code>50</code></td><td>Max backend server log entries (from X-Piwi-Logs header) included.</td></tr><tr><td><code id="piwi-ai-max-server-log-entry-chars">PIWI_AI_MAX_SERVER_LOG_ENTRY_CHARS</code></td><td><code>1000</code></td><td>Max characters per backend server log entry.</td></tr><tr><td><code id="piwi-ai-max-server-trace-spans">PIWI_AI_MAX_SERVER_TRACE_SPANS</code></td><td><code>40</code></td><td>Max backend server spans (from X-Piwi-Trace header) included in AI diagnosis (0 disables). <em>Added in 0.16.0.</em></td></tr><tr><td><code id="piwi-ai-max-images">PIWI_AI_MAX_IMAGES</code></td><td><code>5</code></td><td>Max screenshots auto-included in the diagnosis context.</td></tr><tr><td><code id="piwi-ai-max-passed-peers">PIWI_AI_MAX_PASSED_PEERS</code></td><td><code>20</code></td><td>Max peer tests in the same file listed when they passed.</td></tr><tr><td><code id="piwi-ai-max-console-window">PIWI_AI_MAX_CONSOLE_WINDOW</code></td><td><code>50</code></td><td>Max console entries of any type in the window before failure.</td></tr><tr><td><code id="piwi-ai-slow-request-ms">PIWI_AI_SLOW_REQUEST_MS</code></td><td><code>1500</code></td><td>Network request duration (ms) threshold for flagging as slow.</td></tr><tr><td><code id="piwi-ai-max-trace-actions">PIWI_AI_MAX_TRACE_ACTIONS</code></td><td><code>10</code></td><td>Max actions extracted from trace ZIP for failing-action context (0 disables).</td></tr><tr><td><code id="piwi-ai-trace-dom-chars">PIWI_AI_TRACE_DOM_CHARS</code></td><td><code>6000</code></td><td>Max characters for the trace-derived DOM/ARIA excerpt in failing-action context.</td></tr><tr><td><code id="piwi-ai-max-trace-stack-frames">PIWI_AI_MAX_TRACE_STACK_FRAMES</code></td><td><code>10</code></td><td>Max call-stack frames (with source windows) from the trace call-stack section (0 disables).</td></tr><tr><td><code id="piwi-ai-max-trace-network-requests">PIWI_AI_MAX_TRACE_NETWORK_REQUESTS</code></td><td><code>20</code></td><td>Max requests included from the trace network stream (0 disables).</td></tr><tr><td><code id="piwi-ai-max-dom-snapshot-chars">PIWI_AI_MAX_DOM_SNAPSHOT_CHARS</code></td><td><code>8000</code></td><td>Max characters of the failure-time DOM snapshot rendered from the trace (0 disables).</td></tr><tr><td><code id="piwi-ai-image-max-edge">PIWI_AI_IMAGE_MAX_EDGE</code></td><td><code>1920</code></td><td>Screenshots are downscaled to at most this many pixels on the long edge before being sent.</td></tr></tbody></table><p>See <a href="./ai-diagnosis.html#context-limits-and-token-cost">AI diagnosis → Context limits</a> for section-by-section guidance.</p><h2 id="ingest-limits" tabindex="-1">Ingest limits <a class="header-anchor" href="#ingest-limits" aria-label="Permalink to &quot;Ingest limits&quot;">​</a></h2><p>Caps applied to per-execution payloads (console output, steps, ARIA snapshots, error text, source snippets) before they are stored. They bound database growth against verbose or hostile submitters; values above each limit are truncated with a visible marker. Distinct from the <code>PIWI_AI_MAX_*</code> limits, which bound what enters an AI diagnosis prompt — the storage defaults sit at or above the AI maxima so the AI limits stay the binding constraint for prompts. Environment-only (no settings UI).</p><table tabindex="0"><thead><tr><th>Variable</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code id="piwi-ingest-max-console-entries">PIWI_INGEST_MAX_CONSOLE_ENTRIES</code></td><td><code>200</code></td><td>Max console entries stored per test execution.</td></tr><tr><td><code id="piwi-ingest-max-console-entry-chars">PIWI_INGEST_MAX_CONSOLE_ENTRY_CHARS</code></td><td><code>2000</code></td><td>Max characters stored per console entry.</td></tr><tr><td><code id="piwi-ingest-max-steps">PIWI_INGEST_MAX_STEPS</code></td><td><code>500</code></td><td>Max test steps stored per execution.</td></tr><tr><td><code id="piwi-ingest-max-step-events">PIWI_INGEST_MAX_STEP_EVENTS</code></td><td><code>1000</code></td><td>Max step events stored per execution.</td></tr><tr><td><code id="piwi-ingest-max-aria-chars">PIWI_INGEST_MAX_ARIA_CHARS</code></td><td><code>100000</code></td><td>Max characters of the ARIA snapshot stored per failing execution.</td></tr><tr><td><code id="piwi-ingest-max-error-chars">PIWI_INGEST_MAX_ERROR_CHARS</code></td><td><code>20000</code></td><td>Max characters of error text stored per execution (head and tail are kept).</td></tr><tr><td><code id="piwi-ingest-max-sample-error-chars">PIWI_INGEST_MAX_SAMPLE_ERROR_CHARS</code></td><td><code>50000</code></td><td>Max characters of the sample error stored per failure cluster.</td></tr><tr><td><code id="piwi-ingest-max-test-source-chars">PIWI_INGEST_MAX_TEST_SOURCE_CHARS</code></td><td><code>50000</code></td><td>Max characters of the test source snippet stored per failing execution.</td></tr><tr><td><code id="piwi-ingest-max-source-frames">PIWI_INGEST_MAX_SOURCE_FRAMES</code></td><td><code>8</code></td><td>Max source stack frames stored per failing execution.</td></tr><tr><td><code id="piwi-ingest-max-source-frame-chars">PIWI_INGEST_MAX_SOURCE_FRAME_CHARS</code></td><td><code>4000</code></td><td>Max characters per stored source frame snippet.</td></tr></tbody></table><h2 id="timeline-markers" tabindex="-1">Timeline markers <a class="header-anchor" href="#timeline-markers" aria-label="Permalink to &quot;Timeline markers&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Variable</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code id="piwi-auto-markers">PIWI_AUTO_MARKERS</code></td><td><code>true</code></td><td>Automatically create a timeline marker when a run’s environment, Playwright version, or reporter version changes from the previous run (default: enabled). Set to false to disable. Only the exact value <code>false</code> disables auto-markers. See <a href="./timeline-markers.html">details</a>.</td></tr></tbody></table><h2 id="email-smtp" tabindex="-1">Email (SMTP) <a class="header-anchor" href="#email-smtp" aria-label="Permalink to &quot;Email (SMTP)&quot;">​</a></h2><p>Required for email notifications and account flows (verification, password reset, invites). Set via environment only.</p><table tabindex="0"><thead><tr><th>Variable</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code id="piwi-smtp-host">PIWI_SMTP_HOST</code></td><td>—</td><td>SMTP server hostname for outbound email.</td></tr><tr><td><code id="piwi-smtp-port">PIWI_SMTP_PORT</code></td><td><code>587</code></td><td>SMTP port (default 587; 465 for implicit TLS).</td></tr><tr><td><code id="piwi-smtp-user">PIWI_SMTP_USER</code></td><td>—</td><td>SMTP username.</td></tr><tr><td><code id="piwi-smtp-pass">PIWI_SMTP_PASS</code></td><td>—</td><td>SMTP password. Never returned by the API.</td></tr><tr><td><code id="piwi-smtp-from">PIWI_SMTP_FROM</code></td><td>—</td><td>From address for outbound email (e.g. <a href="mailto:noreply@example.com" target="_blank" rel="noreferrer">noreply@example.com</a>).</td></tr><tr><td><code id="piwi-smtp-from-name">PIWI_SMTP_FROM_NAME</code></td><td><code>Piwi Dashboard</code></td><td>Display name for the from address (optional).</td></tr><tr><td><code id="piwi-smtp-secure">PIWI_SMTP_SECURE</code></td><td>—</td><td>Set to &quot;true&quot; for implicit TLS on port 465 (default false → STARTTLS/plain). Defaults to on when the port is 465, off otherwise.</td></tr></tbody></table><p>Email sending activates once <code>PIWI_SMTP_HOST</code>, <code>PIWI_SMTP_USER</code>, <code>PIWI_SMTP_PASS</code> and <code>PIWI_SMTP_FROM</code> are all set. See <a href="./notifications.html">Notifications</a> for channels and subscriptions.</p><h2 id="failure-clustering" tabindex="-1">Failure clustering <a class="header-anchor" href="#failure-clustering" aria-label="Permalink to &quot;Failure clustering&quot;">​</a></h2><p>Tunes the similarity thresholds used when grouping failures into clusters by their error fingerprint (and optional embeddings). Only used when an embedding model is configured.</p><table tabindex="0"><thead><tr><th>Variable</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code id="piwi-cluster-similarity-threshold">PIWI_CLUSTER_SIMILARITY_THRESHOLD</code></td><td><code>0.92</code></td><td>Cosine similarity (0–1) above which two failure embeddings merge into one cluster. Must be greater than 0 and at most 1; invalid values fall back to the default.</td></tr><tr><td><code id="piwi-cluster-suggest-threshold">PIWI_CLUSTER_SUGGEST_THRESHOLD</code></td><td><code>0.80</code></td><td>Similarity at which a failure is suggested (not auto-merged) as related to a cluster. Capped at the merge threshold.</td></tr></tbody></table><p>See <a href="./ai-diagnosis.html#failure-clustering">AI diagnosis → Failure clustering</a>.</p><h2 id="backend-logs" tabindex="-1">Backend logs <a class="header-anchor" href="#backend-logs" aria-label="Permalink to &quot;Backend logs&quot;">​</a></h2><p>Controls the <code>X-Piwi-Logs</code> response-header capture that attaches backend logs to test failures. See <a href="./backend-logs.html">Backend logs</a>.</p><table tabindex="0"><thead><tr><th>Variable</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code id="piwi-test-logs-disabled">PIWI_TEST_LOGS_DISABLED</code></td><td>—</td><td>Disable X-Piwi-Logs response header emission (default: auto-disabled in production, enabled in development). Unset: capture is on in development and off in production builds; <code>true</code> forces it off everywhere, <code>false</code> forces it on even in production. See <a href="./backend-logs.html">details</a>.</td></tr></tbody></table><h2 id="build-time" tabindex="-1">Build-time <a class="header-anchor" href="#build-time" aria-label="Permalink to &quot;Build-time&quot;">​</a></h2><p>These affect how the app is built rather than how a running instance behaves, and are mostly for contributors.</p><table tabindex="0"><thead><tr><th>Variable</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code id="piwi-build-dir">PIWI_BUILD_DIR</code></td><td>—</td><td>Overrides the Nuxt build output directory. Used by the test harness to isolate parallel builds.</td></tr><tr><td><code id="piwi-build-sha">PIWI_BUILD_SHA</code></td><td>—</td><td>Commit SHA baked into the build for provenance. Shown on Settings → About. Set as a build-time arg.</td></tr><tr><td><code id="piwi-demo-mode">PIWI_DEMO_MODE</code></td><td>—</td><td>Set to &quot;true&quot; to build the standalone client-side demo SPA (no server).</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p><code>PIWI_BASE_URL</code>, <code>PIWI_POSTGRES_TEST_URL</code>, <code>PIWI_S3_TEST_BUCKET</code>, <code>PIWI_S3_TEST_REGION</code>, <code>PIWI_S3_TEST_ACCESS_KEY_ID</code>, <code>PIWI_S3_TEST_SECRET_ACCESS_KEY</code>, <code>PIWI_S3_TEST_ENDPOINT</code>, <code>PIWI_MAILPIT_URL</code>, <code>PIWI_MAILPIT_SMTP_PORT</code>, <code>PIWI_EMAIL_SERVER_URL</code>, <code>PIWI_DESKTOP_TOKEN</code> exist only for the functional test harness and are not used by a normal deployment.</p></div>',51))])}const g=o(l,[["render",h]]);export{b as __pageData,g as default};
